bot.js.content:
import { Bot } from "grammy";

import { registerCommands } from "./commands/loader.js";
import { registerWelcomeHandlers } from "./features/welcome.js";
import { registerCallbackHandlers } from "./features/callbacks.js";
import { ensureDbReady } from "./lib/db.js";
import { getBotProfile } from "./lib/botProfile.js";
import { safeErr } from "./lib/safeErr.js";

export function createBot(token) {
  const bot = new Bot(token);

  bot.use(async (ctx, next) => {
    const chatId = ctx.chat?.id;
    const userId = ctx.from?.id;
    const updateId = ctx.update?.update_id;

    if (ctx.update?.message?.text?.startsWith?.("/")) {
      const cmd = String(ctx.update.message.text || "").split(/\s+/)[0];
      console.log("[cmd] entry", { cmd, chatId, userId, updateId });
    }

    try {
      await next();
    } catch (e) {
      console.error("[middleware] error", { err: safeErr(e), chatId, userId, updateId });
      throw e;
    }
  });

  bot.use(async (ctx, next) => {
    if (!ctx.chat?.id) return next();
    try {
      await ensureDbReady();
    } catch (e) {
      console.error("[db] ensureDbReady failed", { err: safeErr(e) });
      // Let command handlers show user-friendly errors if they hit DB.
    }
    return next();
  });

  // Commands first (middleware order matters)
  registerCommands(bot);

  // Non-command features after
  registerCallbackHandlers(bot);
  registerWelcomeHandlers(bot);

  bot.on("message:text", async (ctx, next) => {
    const text = ctx.message?.text || "";
    if (text.startsWith("/")) return next();
    // No AI catch-all for this bot. Keep behavior deterministic.
    return next();
  });

  console.log("[bot] profile", { profile: getBotProfile() });

  return bot;
}

admin.js.content:
import { isAdminForChatOrOverride } from "../services/authz.js";
import { isPrivateChat } from "../lib/tg.js";
import { getChatSettings } from "../services/chats.js";

export default function register(bot) {
  bot.command("admin", async (ctx) => {
    if (isPrivateChat(ctx)) {
      return ctx.reply(
        "Admin tools are mostly used inside a group. If you want to manage FAQ or suggestions in private, first set your default community by using /faq in the group once."
      );
    }

    const chatId = ctx.chat?.id;
    if (!chatId) return;

    const ok = await isAdminForChatOrOverride(chatId, ctx.from?.id, ctx);
    if (!ok) return ctx.reply("Admin only.");

    const s = await getChatSettings(chatId);
    const we = !!s?.settings?.welcomeEnabled;

    await ctx.reply(
      "Admin panel\n\n" +
        `Welcome enabled: ${we}\n` +
        "Commands: /setrules, /setwelcome, /welcome_on, /welcome_off, /announce, /announce_targets, /audit, /warn"
    );
  });
}

announce.js.content:
import { InlineKeyboard } from "grammy";

import { isAdminForChatOrOverride, isGlobalAdmin } from "../services/authz.js";
import { isPrivateChat } from "../lib/tg.js";
import { setPendingInput } from "../services/pending.js";
import { listAnnounceTargets } from "../services/announcements.js";

export default function register(bot) {
  bot.command("announce", async (ctx) => {
    const userId = ctx.from?.id;
    const chatId = ctx.chat?.id;
    if (!userId || !chatId) return;

    if (!isPrivateChat(ctx)) {
      const ok = await isAdminForChatOrOverride(chatId, userId, ctx);
      if (!ok) return ctx.reply("Admin only.");

      await setPendingInput({ chatId, userId, kind: "announce_text", ttlSeconds: 120, meta: { targets: [chatId] } });
      return ctx.reply("Send the announcement text as your next message within 2 minutes.");
    }

    // Private: only allow if global admin and targets exist
    if (!isGlobalAdmin(userId)) {
      return ctx.reply("In private chat, /announce is available only to global admins (BOT_ADMIN_IDS).");
    }

    const targets = await listAnnounceTargets(userId);
    if (!targets.length) {
      return ctx.reply("No announcement targets configured. Use /announce_targets add <chatId>.");
    }

    const kb = new InlineKeyboard();
    for (const t of targets.slice(0, 12)) {
      kb.text(String(t.chatId), `ann:t:${t.chatId}`).row();
    }

    await setPendingInput({ chatId, userId, kind: "announce_pick", ttlSeconds: 120 });
    return ctx.reply("Pick a target chat:", { reply_markup: kb });
  });
}

announce_targets.js.content:
import { isPrivateChat } from "../lib/tg.js";
import { isGlobalAdmin } from "../services/authz.js";
import { addAnnounceTarget, removeAnnounceTarget, listAnnounceTargets } from "../services/announcements.js";

function getArgText(ctx) {
  const t = String(ctx.message?.text || "");
  const parts = t.split(/\s+/);
  parts.shift();
  return parts.join(" ").trim();
}

export default function register(bot) {
  bot.command("announce_targets", async (ctx) => {
    // This command is intentionally simple: global overrides can manage; otherwise use in group.
    // Real-world admin validation for arbitrary targets can be added later.

    const arg = getArgText(ctx);
    const userId = ctx.from?.id;
    if (!userId) return;

    // Safer default: only global admins can manage targets in private.
    if (isPrivateChat(ctx) && !isGlobalAdmin(userId)) {
      return ctx.reply(
        "For safety, manage announcement targets as a global admin (BOT_ADMIN_IDS) or run /announce in the group to send to that group."
      );
    }

    if (!arg) {
      const targets = await listAnnounceTargets(userId);
      if (!targets.length) return ctx.reply("No announcement targets configured.");
      return ctx.reply("Announcement targets:\n" + targets.map((t) => String(t.chatId)).join("\n"));
    }

    const m = arg.match(/^(add|remove)\s+(-?\d+)$/i);
    if (!m) {
      return ctx.reply("Usage: /announce_targets add <chatId> OR /announce_targets remove <chatId>");
    }

    const op = m[1].toLowerCase();
    const chatId = Number(m[2]);

    if (op === "add") {
      await addAnnounceTarget(userId, chatId);
      return ctx.reply("Target added.");
    }

    await removeAnnounceTarget(userId, chatId);
    return ctx.reply("Target removed.");
  });
}

audit.js.content:
import { isAdminForChatOrOverride } from "../services/authz.js";
import { listAudit } from "../services/audit.js";
import { isPrivateChat } from "../lib/tg.js";

export default function register(bot) {
  bot.command("audit", async (ctx) => {
    if (isPrivateChat(ctx)) {
      return ctx.reply("Run /audit in a group to view that chat's audit log.");
    }

    const chatId = ctx.chat?.id;
    if (!chatId) return;

    const ok = await isAdminForChatOrOverride(chatId, ctx.from?.id, ctx);
    if (!ok) return ctx.reply("Admin only.");

    const rows = await listAudit(chatId, 10);
    if (!rows.length) return ctx.reply("No audit entries yet.");

    const text = rows
      .map((a) => {
        const who = a.byUsername ? `@${a.byUsername}` : String(a.byUserId || "");
        return `${new Date(a.createdAt).toISOString()} ${a.action} by ${who}`;
      })
      .join("\n");

    await ctx.reply(text);
  });
}

faq.js.content:
import { InlineKeyboard } from "grammy";

import { searchFaqs, listFaqsForChat, getFaqById } from "../services/faqs.js";
import { getUserDefaultChatId, setUserDefaultChatId } from "../services/userContext.js";
import { isPrivateChat } from "../lib/tg.js";

function getArgs(ctx) {
  const t = String(ctx.message?.text || "");
  const parts = t.split(/\s+/);
  parts.shift();
  return parts.join(" ").trim();
}

export default function register(bot) {
  bot.command("faq", async (ctx) => {
    const args = getArgs(ctx);
    const isPrivate = isPrivateChat(ctx);

    if (!isPrivate) {
      // In group: set user's default context to this chat
      if (ctx.from?.id && ctx.chat?.id) await setUserDefaultChatId(ctx.from.id, ctx.chat.id);
      return ctx.reply("Got it. In DMs, use /faq to browse this chat's FAQ.");
    }

    const chatId = await getUserDefaultChatId(ctx.from?.id);
    if (!chatId) {
      return ctx.reply(
        "I do not know which community FAQ to show yet. Use /faq in the group once to set your default community."
      );
    }

    if (args) {
      const hits = await searchFaqs(Number(chatId), args, 5);
      if (!hits.length) return ctx.reply("No matches found.");

      const kb = new InlineKeyboard();
      for (const f of hits) {
        kb.text(f.question.slice(0, 48) || f.faqId, `faq:view:${f.faqId}`).row();
      }

      return ctx.reply("Top matches:", { reply_markup: kb });
    }

    const faqs = await listFaqsForChat(Number(chatId), 12);
    if (!faqs.length) return ctx.reply("No FAQ entries yet.");

    const kb = new InlineKeyboard();
    for (const f of faqs) {
      kb.text(f.question.slice(0, 48) || f.faqId, `faq:view:${f.faqId}`).row();
    }

    return ctx.reply("FAQ:", { reply_markup: kb });
  });
}

faq_add.js.content:
import { parseQaPipe } from "../lib/text.js";
import { isGlobalOrChatAdminForPrivateTarget } from "../services/authz.js";
import { addFaq } from "../services/faqs.js";
import { getUserDefaultChatId } from "../services/userContext.js";
import { isPrivateChat } from "../lib/tg.js";

function getArgText(ctx) {
  const t = String(ctx.message?.text || "");
  const parts = t.split(/\s+/);
  parts.shift();
  return parts.join(" ").trim();
}

export default function register(bot) {
  bot.command("faq_add", async (ctx) => {
    const isPrivate = isPrivateChat(ctx);
    let chatId = ctx.chat?.id;

    if (isPrivate) {
      chatId = await getUserDefaultChatId(ctx.from?.id);
      if (!chatId) return ctx.reply("In private chat, first set a default community by using /faq in a group.");
    }

    const ok = await isGlobalOrChatAdminForPrivateTarget(Number(chatId), ctx.from?.id, ctx);
    if (!ok) return ctx.reply("Admin only.");

    const arg = getArgText(ctx);
    const parsed = parseQaPipe(arg);
    if (!parsed) return ctx.reply("Usage: /faq_add <question> | <answer>");

    const faq = await addFaq(Number(chatId), parsed.question, parsed.answer);
    await ctx.reply(`FAQ added. id=${faq.faqId}`);
  });
}

