loader.js.content:
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";

export function registerCommands(bot) {
  const dir = path.dirname(fileURLToPath(import.meta.url));

  const files = fs
    .readdirSync(dir)
    .filter(
      (f) =>
        f.endsWith(".js") &&
        f !== "loader.js" &&
        !f.startsWith("_")
    )
    .sort();

  for (const f of files) {
    const url = pathToFileURL(path.join(dir, f)).href;
    import(url)
      .then((mod) => {
        const fn = mod?.default || mod?.register;
        if (typeof fn === "function") fn(bot);
        else console.warn("[commands] skipped (no register export)", { file: f });
      })
      .catch((e) => {
        console.error("[commands] failed to load", { file: f, err: e?.message || String(e) });
      });
  }
}

rules.js.content:
import { getChatSettings } from "../services/chats.js";
import { getUserDefaultChatId, setUserDefaultChatId } from "../services/userContext.js";
import { isPrivateChat } from "../lib/tg.js";

function rulesFallback() {
  return "No rules have been set for this chat yet.";
}

export default function register(bot) {
  bot.command("rules", async (ctx) => {
    const isPrivate = isPrivateChat(ctx);

    let targetChatId = ctx.chat?.id;

    if (isPrivate) {
      const d = await getUserDefaultChatId(ctx.from?.id);
      if (!d) {
        return ctx.reply(
          "I do not know which community you mean yet. Use /faq in a group once, or ask an admin to configure the bot in your group."
        );
      }
      targetChatId = Number(d);
    }

    const s = await getChatSettings(targetChatId);
    const rules = s?.settings?.rulesText;

    await ctx.reply(rules && String(rules).trim() ? String(rules).trim() : rulesFallback());
  });
}

setrules.js.content:
import { isAdminForChatOrOverride } from "../services/authz.js";
import { upsertChatSettings } from "../services/chats.js";
import { setPendingInput } from "../services/pending.js";
import { isPrivateChat } from "../lib/tg.js";

function getArgText(ctx) {
  const t = String(ctx.message?.text || "");
  const parts = t.split(/\s+/);
  parts.shift();
  return parts.join(" ").trim();
}

export default function register(bot) {
  bot.command("setrules", async (ctx) => {
    const chatId = ctx.chat?.id;
    if (!chatId) return;

    if (isPrivateChat(ctx)) {
      return ctx.reply("Run /setrules inside the group where you want to set rules.");
    }

    const ok = await isAdminForChatOrOverride(chatId, ctx.from?.id, ctx);
    if (!ok) return ctx.reply("Admin only. You must be a chat admin to use this command.");

    const arg = getArgText(ctx);
    if (arg) {
      await upsertChatSettings(chatId, { rulesText: arg });
      return ctx.reply("Rules updated.");
    }

    await setPendingInput({
      chatId,
      userId: ctx.from?.id,
      kind: "setrules",
      ttlSeconds: 60
    });

    return ctx.reply("Send the rules text as your next message within 60 seconds.");
  });
}

